<?php
namespace App\Actions;
use App\Models\{InventoryMovement,MaterialPurchase,MaterialPurchaseItem};use Illuminate\Support\Facades\DB;
class UpdateMaterialPurchaseAction{public function execute(MaterialPurchase $purchase,array $data): MaterialPurchase{return DB::transaction(function() use($purchase,$data){InventoryMovement::where('source_type',MaterialPurchaseItem::class)->whereIn('source_id',$purchase->items()->pluck('id'))->delete();$purchase->items()->delete();$items=$data['items'];$tagIds=$data['tag_ids']??[];unset($data['items'],$data['tag_ids']);$purchase->update($data+['total_amount'=>0]);$total=0;foreach($items as $item){$line=round((float)$item['quantity']*(float)$item['unit_price'],2);$purchaseItem=$purchase->items()->create($item+['total_price'=>$line]);InventoryMovement::create(['project_id'=>$purchase->project_id,'material_id'=>$item['material_id'],'date'=>$purchase->date,'type'=>'in','quantity'=>$item['quantity'],'unit_price'=>$item['unit_price'],'amount'=>$line,'source_type'=>MaterialPurchaseItem::class,'source_id'=>$purchaseItem->id,'comment'=>'Покупка материалов #'.$purchase->id]);$total+=$line;}$purchase->update(['total_amount'=>round($total,2)]);$purchase->tags()->sync($tagIds);return $purchase->load('items','tags');});}}
